240: fn event_handler(
241:     handle: Handle,
242:     event_type: EventTapType,
243:     pressed_key: Option<PressedKey>,
244:     modifiers: KeyModifier,
245: ) -> bool {
246:     unsafe {
247:         let pressed_key_code = pressed_key.and_then(|p| match p {
248:             PressedKey::Char(c) => Some(c),
249:             _ => None,
250:         });
251: 
252:         if event_type == EventTapType::FlagsChanged {
253:             if modifiers.is_empty() {
254:                 // Modifier keys are released
255:                 if HOTKEY_MATCHING && !HOTKEY_MATCHING_CIRCUIT_BREAK {
256:                     toggle_vietnamese();
257:                 }
258:                 HOTKEY_MODIFIERS = KeyModifier::MODIFIER_NONE;
259:                 HOTKEY_MATCHING = false;
260:                 HOTKEY_MATCHING_CIRCUIT_BREAK = false;
261:             } else {
262:                 HOTKEY_MODIFIERS.set(modifiers, true);
263:             }
264:         }
265: 
266:         let is_hotkey_matched = INPUT_STATE
267:             .get_hotkey()
268:             .is_match(HOTKEY_MODIFIERS, pressed_key_code);
269:         if HOTKEY_MATCHING && !is_hotkey_matched {
270:             HOTKEY_MATCHING_CIRCUIT_BREAK = true;
271:         }
272:         HOTKEY_MATCHING = is_hotkey_matched;
273: 
274:         // If the hotkey matched on a key press, toggle immediately and
275:         // suppress the event so macOS does not insert the character
276:         // (e.g. Option+Z → Ω).  Set HOTKEY_MATCHING_CIRCUIT_BREAK so
277:         // the FlagsChanged handler does not toggle again on key release.
278:         if is_hotkey_matched && pressed_key_code.is_some() {
279:             toggle_vietnamese();
280:             HOTKEY_MATCHING_CIRCUIT_BREAK = true;
281:             return true;
282:         }
283: 
284:         match pressed_key {
285:             Some(pressed_key) => {
286:                 match pressed_key {
287:                     PressedKey::Raw(raw_keycode) => {
288:                         if raw_keycode == RAW_KEY_GLOBE {
289:                             toggle_vietnamese();
290:                             return true;
291:                         }
292:                         if raw_keycode == RAW_ARROW_UP || raw_keycode == RAW_ARROW_DOWN {
293:                             INPUT_STATE.new_word();
294:                         }
295:                         if raw_keycode == RAW_ARROW_LEFT || raw_keycode == RAW_ARROW_RIGHT {
296:                             // TODO: Implement a better cursor tracking on each word here
297:                             INPUT_STATE.new_word();
298:                         }
299:                     }
300:                     PressedKey::Char(keycode) => {
301:                         if INPUT_STATE.is_enabled() {
302:                             match keycode {
303:                                 KEY_ENTER | KEY_TAB | KEY_SPACE | KEY_ESCAPE => {
304:                                     let typing_buffer = INPUT_STATE.get_typing_buffer();
305:                                     let display_word = INPUT_STATE.get_displaying_word();
306:                                     let is_valid_word = vi::validation::is_valid_word(display_word);
307:                                     let is_allowed_word = INPUT_STATE.is_allowed_word(display_word);
308:                                     if should_restore_transformed_word(
309:                                         INPUT_STATE.get_method(),
310:                                         typing_buffer,
311:                                         display_word,
312:                                         is_valid_word,
313:                                         is_allowed_word,
314:                                     ) {
315:                                         do_restore_word(handle, modifiers.is_capslock());
316:                                     }
317: 
318:                                     if INPUT_STATE.previous_word_is_stop_tracking_words() {
319:                                         INPUT_STATE.clear_previous_word();
320:                                     }
321: 
322:                                     if keycode == KEY_TAB || keycode == KEY_SPACE {
323:                                         if let Some(macro_target) = INPUT_STATE.get_macro_target() {
324:                                             debug!("Macro: {}", macro_target);
325:                                             do_macro_replace(handle, &macro_target)
326:                                         }
327:                                     }
328: 
329:                                     let had_content = !INPUT_STATE.is_buffer_empty();
330:                                     INPUT_STATE.new_word();
331:                                     if had_content && (keycode == KEY_SPACE || keycode == KEY_TAB) {
332:                                         INPUT_STATE.mark_resumable();
333:                                     }
334:                                 }
335:                                 KEY_DELETE => {
336:                                     if !modifiers.is_empty() && !modifiers.is_shift() {
337:                                         INPUT_STATE.new_word();
338:                                     } else if INPUT_STATE.is_buffer_empty() {
339:                                         // Buffer is empty — the user just started a new
340:                                         // word (e.g. after space).  Try to resume editing
341:                                         // the previous word so backspace + retype works.
342:                                         // If resume fails, reset to a fresh tracking state
343:                                         // so the next keystrokes are processed (e.g. after
344:                                         // stop_tracking from a duplicate pattern like "ww").
345:                                         if !INPUT_STATE.try_resume_previous_word() {
346:                                             INPUT_STATE.new_word();
347:                                         }
348:                                     } else {
349:                                         INPUT_STATE.pop();
350:                                         if !INPUT_STATE.is_buffer_empty() {
351:                                             return do_transform_keys(
352:                                                 handle,
353:                                                 true,
354:                                                 modifiers.is_capslock(),
355:                                             );
356:                                         }
357:                                     }
358:                                 }
359:                                 c => {
360:                                     if "()[]{}<>/\\!@#$%^&*-_=+|~`,.;'\"/".contains(c)
361:                                         || (c.is_numeric() && modifiers.is_shift())
362:                                     {
363:                                         // If special characters detected, dismiss the current tracking word
364:                                         if c.is_numeric() {
365:                                             INPUT_STATE.push(c);
366:                                         }
367:                                         INPUT_STATE.new_word();
368:                                     } else {
369:                                         // Otherwise, process the character
370:                                         if modifiers.is_super() || modifiers.is_alt() {
371:                                             INPUT_STATE.new_word();
372:                                         } else if INPUT_STATE.is_tracking() {
373:                                             INPUT_STATE.push(normalize_input_char(
374:                                                 c,
375:                                                 modifiers.is_shift(),
376:                                             ));
377:                                             let ret = do_transform_keys(
378:                                                 handle,
379:                                                 false,
380:                                                 modifiers.is_capslock(),
381:                                             );
382:                                             INPUT_STATE.stop_tracking_if_needed();
383:                                             return ret;
384:                                         }
385:                                     }
386:                                 }
387:                             }
388:                         } else {
389:                             match keycode {
390:                                 KEY_ENTER | KEY_TAB | KEY_SPACE | KEY_ESCAPE => {
391:                                     INPUT_STATE.new_word();
392:                                 }
393:                                 _ => {
394:                                     if !modifiers.is_empty() {
395:                                         INPUT_STATE.new_word();
396:                                     }
397:                                 }
398:                             }
399:                         }
400:                     }
401:                 };
402:             }
403:             None => {
404:                 let previous_modifiers = INPUT_STATE.get_previous_modifiers();
405:                 if previous_modifiers.is_empty() {
406:                     if modifiers.is_control() {
407:                         if !INPUT_STATE.get_typing_buffer().is_empty() {
408:                             do_restore_word(handle, modifiers.is_capslock());
409:                         }
410:                         INPUT_STATE.set_temporary_disabled();
411:                     }
412:                     if modifiers.is_super() || event_type == EventTapType::Other {
413:                         INPUT_STATE.new_word();
414:                     }
415:                 }
416:             }
417:         }
418:         INPUT_STATE.save_previous_modifiers(modifiers);
419:     }
420:     false
421: }
