76: /// On macOS, current_exe gives path to /Applications/Example.app/MacOS/Example but this results in seeing a Unix Executable in macOS login items. It must be: /Applications/Example.app
77: /// If it didn't find exactly a single occurrence of .app, it will default to exe path to not break it.
78: fn get_current_app_path() -> String {
79:     let current_exe = current_exe().unwrap();
80:     let exe_path = current_exe.canonicalize().unwrap().display().to_string();
81:     let parts: Vec<&str> = exe_path.split(".app/").collect();
82:     return if parts.len() == 2 {
83:         format!("{}.app", parts.get(0).unwrap().to_string())
84:     } else {
85:         exe_path
86:     };
87: }
