197: pub fn send_backspace(handle: Handle, count: usize) -> Result<(), ()> {
198:     let null_event_source = ptr::null_mut() as *mut sys::CGEventSource;
199:     let (event_bs_down, event_bs_up) = unsafe {
200:         (
201:             CGEventCreateKeyboardEvent(null_event_source, KeyCode::DELETE, true),
202:             CGEventCreateKeyboardEvent(null_event_source, KeyCode::DELETE, false),
203:         )
204:     };
205:     for _ in 0..count {
206:         unsafe {
207:             CGEventTapPostEvent(handle, event_bs_down);
208:             CGEventTapPostEvent(handle, event_bs_up);
209:         }
210:     }
211:     Ok(())
212: }
