306: 
307:             let mut modifiers = KeyModifier::new();
308:             let flags = event.get_flags();
309:             if flags.contains(CGEventFlags::CGEventFlagShift) {
310:                 modifiers.add_shift();
311:             }
312:             if flags.contains(CGEventFlags::CGEventFlagAlphaShift) {
313:                 modifiers.add_capslock();
314:             }
315:             if flags.contains(CGEventFlags::CGEventFlagControl) {
316:                 modifiers.add_control();
317:             }
318:             if flags.contains(CGEventFlags::CGEventFlagCommand) {
319:                 modifiers.add_super();
320:             }
321:             if flags.contains(CGEventFlags::CGEventFlagAlternate) {
322:                 modifiers.add_alt();
323:             }
324:             if flags.eq(&CGEventFlags::CGEventFlagNonCoalesced)
325:                 || flags.eq(&CGEventFlags::CGEventFlagNull)
326:             {
327:                 modifiers = KeyModifier::MODIFIER_NONE;
328:             }
329: 
330:             let event_tap_type: EventTapType = EventTapType::from(event.get_type());
331:             match event_tap_type {
332:                 EventTapType::KeyDown => {
333:                     let source_state_id =
334:                         event.get_integer_value_field(EventField::EVENT_SOURCE_STATE_ID);
335:                     if source_state_id == 1 {
336:                         let key_code = event
337:                             .get_integer_value_field(EventField::KEYBOARD_EVENT_KEYCODE)
338:                             as CGKeyCode;
339: 
340:                         if callback(proxy, event_tap_type, get_char(key_code), modifiers) {
341:                             // block the key if already processed
342:                             return None;
343:                         }
344:                     }
345:                 }
346:                 EventTapType::FlagsChanged => {
347:                     callback(proxy, event_tap_type, None, modifiers);
348:                 }
349:                 _ => {
350:                     callback(proxy, event_tap_type, None, KeyModifier::new());
351:                 }
352:             }
353:             Some(event.to_owned())
354:         },
355:     ) {
356:         unsafe {
357:             let loop_source = event_tap.mach_port.create_runloop_source(0).expect("Cannot start event tap. Make sure you have granted Accessibility Access for the application.");
358:             current.add_source(&loop_source, kCFRunLoopCommonModes);
359:             event_tap.enable();
360:             CFRunLoop::run_current();
361:         }
362:     }
363: }
